mapper.update:
-- 1. 기존 스냅샷 삭제 DELETE FROM d21_제조지시VLR_SNAPSHOT WHERE YYYYMM = #{yyyymm} AND SITE = #{site}; DELETE FROM d22_RUN제조VLR_SNAPSHOT WHERE YYYYMM = #{yyyymm} AND SITE = #{site}; DELETE FROM d27_내포장MST_SNAPSHOT WHERE YYYYMM = #{yyyymm} AND SITE = #{site};
-- 2. d21 스냅샷 (투입: 공정코드='010', 불량FRONT: 전체공정) -- 작업시작 BETWEEN 해당월 범위 INSERT INTO d21_제조지시VLR_SNAPSHOT ( YYYYMM, SITE, SNAPSHOT_DT, 공장코드, LOT_NO, 공정코드, 순서, 레시피, RUN_NO, BEF_공정코드, NXT_공정코드, 작업시작, 시작시각, 작업종료, 종료시각, 작업일자, 작업자, 작업조, Shift, Machine_Code, P_CODE, 공정_비고, 작업구분, 투입수량, 검사수량, 불량수량, 양품수량, CELL수량, 확인자, 특이사항, 재공적용_여부 ) SELECT #{yyyymm}, #{site}, GETDATE(), 공장코드, LOT_NO, 공정코드, 순서, 레시피, RUN_NO, BEF_공정코드, NXT_공정코드, 작업시작, 시작시각, 작업종료, 종료시각, 작업일자, 작업자, 작업조, Shift, Machine_Code, P_CODE, 공정_비고, 작업구분, 투입수량, 검사수량, 불량수량, 양품수량, CELL수량, 확인자, 특이사항, 재공적용_여부 FROM d21_제조지시VLR WHERE 작업시작 BETWEEN #{yyyymm} + '01' AND REPLACE(EOMONTH(DATEFROMPARTS(SUBSTRING(#{yyyymm},1,4), SUBSTRING(#{yyyymm},5,2), 1)),'-','');
-- 3. d22 스냅샷 (불량BACK) -- 작업시작 BETWEEN 해당월 범위 INSERT INTO d22_RUN제조VLR_SNAPSHOT ( YYYYMM, SITE, SNAPSHOT_DT, 공장코드, RUN_NO, 공정코드, 레시피, LOT_NO, LOT_등분, 작업시작, 시작시각, 작업종료, 종료시각, 작업일자, 작업자, 작업조, Machine_Code, SHIFT, 책임자, 책임자시작, 책임자종료, 선임자, P_CODE, 작업구분, 투입수량, 검사수량, 불량수량, 양품수량, 확인자, 특이사항, 차수, 시료수량, IS_AUTO, BATCH_NO ) SELECT #{yyyymm}, #{site}, GETDATE(), 공장코드, RUN_NO, 공정코드, 레시피, LOT_NO, LOT_등분, 작업시작, 시작시각, 작업종료, 종료시각, 작업일자, 작업자, 작업조, Machine_Code, SHIFT, 책임자, 책임자시작, 책임자종료, 선임자, P_CODE, 작업구분, 투입수량, 검사수량, 불량수량, 양품수량, 확인자, 특이사항, 차수, 시료수량, IS_AUTO, BATCH_NO FROM d22_RUN제조VLR WHERE 작업시작 BETWEEN #{yyyymm} + '01' AND REPLACE(EOMONTH(DATEFROMPARTS(SUBSTRING(#{yyyymm},1,4), SUBSTRING(#{yyyymm},5,2), 1)),'-','');
-- 4. d27 스냅샷 (OUT - 대기작업시각 기준, 080000~075959) INSERT INTO d27_내포장MST_SNAPSHOT ( YYYYMM, SITE, SNAPSHOT_DT, 발행일자, 발행구분, PACK_QRNO, 소포장_QRNO, 대포장_QRNO, RUN_ID, 상태코드, PACK상태, 일련번호, Cell수량, Tray수량, Start_Time, End_Time, 유효기간, 유효일자, 발행자, 출하대기여부, 대기작업시각, 대기발행자, 대기승인자, PALLET_NO, 출하여부, 출하작업시각, 재공적용_여부, 생산지시번호, 특이사항 ) SELECT #{yyyymm}, #{site}, GETDATE(), 발행일자, 발행구분, PACK_QRNO, 소포장_QRNO, 대포장_QRNO, RUN_ID, 상태코드, PACK상태, 일련번호, Cell수량, Tray수량, Start_Time, End_Time, 유효기간, 유효일자, 발행자, 출하대기여부, 대기작업시각, 대기발행자, 대기승인자, PALLET_NO, 출하여부, 출하작업시각, 재공적용_여부, 생산지시번호, 특이사항 FROM d27_내포장MST WHERE 대기작업시각 BETWEEN #{yyyymm} + '01 080000' AND FORMAT(DATEADD(MONTH, 1, DATEFROMPARTS(SUBSTRING(#{yyyymm},1,4), SUBSTRING(#{yyyymm},5,2), 1)), 'yyyyMMdd') + ' 075959';

mapper.select:
SELECT HIST_SEQ, CHANGE_DT, CHANGE_TYPE, CHANGE_USER, CHANGE_REASON,
	공장코드, LOT_NO, 공정코드, 순서, 작업구분, 작업시작,
	투입수량, 검사수량, 불량수량, 양품수량, CELL수량
FROM d21_제조지시VLR_HISTORY
WHERE YYYYMM = #{yyyymm}
  AND LOT_NO = #{lotNo}
  AND 공정코드 = #{gongjeong}
ORDER BY CHANGE_DT DESC

SELECT HIST_SEQ, CHANGE_DT, CHANGE_TYPE, CHANGE_USER, CHANGE_REASON,
	공장코드, RUN_NO, 공정코드, 차수, 작업구분, 작업시작,
	투입수량, 검사수량, 불량수량, 양품수량
FROM d22_RUN제조VLR_HISTORY
WHERE YYYYMM = #{yyyymm}
  AND RUN_NO = #{runNo}
  AND 공정코드 = #{gongjeong}
ORDER BY CHANGE_DT DESC
